def _hmac_sign(data: str) -> str:
    """Create HMAC signature for data integrity verification."""
    return hmac.new(
        ENCRYPTION_KEY.encode('utf-8'),
        data.encode('utf-8'),
        hashlib.sha256
    ).hexdigest()


def _encode_sensitive_data(data: str) -> str:
    """
    Encode sensitive data with HMAC for integrity verification.
    In production, use proper encryption (e.g., Fernet from cryptography library).
    """
    signature = _hmac_sign(data)
    payload = json.dumps({"data": data, "sig": signature})
    return payload


def _decode_sensitive_data(encoded: str) -> Optional[str]:
    """Decode and verify sensitive data integrity."""
    try:
        payload = json.loads(encoded)
        data = payload["data"]
        expected_sig = _hmac_sign(data)
        if hmac.compare_digest(payload["sig"], expected_sig):
            return data
        else:
            logger.warning("Data integrity check failed - possible tampering detected")
            return None
    except (json.JSONDecodeError, KeyError) as e:
        logger.error(f"Failed to decode sensitive data: {e}")
        return None


class RedisClusterManager:
    """Manages connections to a Redis cluster with retry logic and health checks."""

    def __init__(self):
        self._cluster: Optional[RedisCluster] = None
        self._connected = False
        self._last_health_check = 0
        self._health_check_interval = 30  # seconds

    def _parse_nodes(self) -> list:
        """Parse Redis node addresses from configuration."""
        nodes = []
        for node_str in REDIS_NODES.split(","):
            node_str = node_str.strip()
            if ":" in node_str:
                host, port = node_str.rsplit(":", 1)
                nodes.append(ClusterNode(host=host, port=int(port)))
            else:
                nodes.append(ClusterNode(host=node_str, port=6379))
        return nodes

    def connect(self, max_retries: int = 3, retry_delay: float = 2.0) -> bool:
        """Establish connection to Redis cluster with retry logic."""
        nodes = self._parse_nodes()

        for attempt in range(1, max_retries + 1):
            try:
                logger.info(
                    f"Attempting to connect to Redis cluster (attempt {attempt}/{max_retries})..."
                )

                connection_kwargs = {
                    "startup_nodes": nodes,
                    "decode_responses": True,
                    "socket_timeout": REDIS_SOCKET_TIMEOUT,
                    "socket_connect_timeout": REDIS_SOCKET_TIMEOUT,
                    "retry_on_timeout": REDIS_RETRY_ON_TIMEOUT,
                    "max_connections": REDIS_MAX_CONNECTIONS,
                    "skip_full_coverage_check": True,
                }

                if REDIS_PASSWORD:
                    connection_kwargs["password"] = REDIS_PASSWORD

                if REDIS_USE_SSL:
                    connection_kwargs["ssl"] = True
                    connection_kwargs["ssl_cert_reqs"] = os.environ.get(
                        "REDIS_SSL_CERT_REQS", "required"
                    )
                    ssl_ca_certs = os.environ.get("REDIS_SSL_CA_CERTS")
                    if ssl_ca_certs:
                        connection_kwargs["ssl_ca_certs"] = ssl_ca_certs
                    ssl_certfile = os.environ.get("REDIS_SSL_CERTFILE")
                    if ssl_certfile:
                        connection_kwargs["ssl_certfile"] = ssl_certfile
                    ssl_keyfile = os.environ.get("REDIS_SSL_KEYFILE")
                    if ssl_keyfile:
                        connection_kwargs["ssl_keyfile"] = ssl_keyfile

                self._cluster = RedisCluster(**connection_kwargs)

                # Verify connection
                self._cluster.ping()
                self._connected = True
                self._last_health_check = time.time()
                logger.info("Successfully connected to Redis cluster")
                return True

            except (ConnectionError, TimeoutError, RedisError) as e:
                logger.error(f"Connection attempt {attempt} failed: {e}")
                if attempt < max_retries:
                    time.sleep(retry_delay * attempt)
                else:
                    logger.critical("All connection attempts to Redis cluster failed")
                    self._connected = False
                    return False

        return False

    def get_client(self) -> Optional[RedisCluster]:
        """Get the Redis cluster client, reconnecting if necessary."""
        if not self._connected or self._cluster is None:
            self.connect()

        # Periodic health check
        current_time = time.time()
        if current_time - self._last_health_check > self._health_check_interval:
            try:
                self._cluster.ping()
                self._last_health_check = current_time
            except (ConnectionError, TimeoutError, RedisError):
                logger.warning("Health check failed, attempting reconnection...")
                self._connected = False
                self.connect()

        return self._cluster

    def disconnect(self):
        """Gracefully disconnect from Redis cluster."""
        if self._cluster:
            try:
                self._cluster.close()
                logger.info("Disconnected from Redis cluster")
            except Exception as e:
                logger.error(f"Error during disconnect: {e}")
            finally:
                self._cluster = None
                self._connected = False

    @property
    def is_connected(self) -> bool:
        return self._connected

    def health_check(self) -> Dict[str, Any]:
        """Perform a health check and return status information."""
        result = {
            "service": SERVICE_NAME,
            "redis_connected": self._connected,
            "timestamp": datetime.utcnow().isoformat(),
        }

        if self._cluster and self._connected:
            try:
                start = time.time()
                self._cluster.ping()
                latency = (time.time() - start) * 1000
                result["redis_latency_ms"] = round(latency, 2)
                result["status"] = "healthy"

                # Get cluster info
                try:
                    cluster_info = self._cluster.cluster_info()
                    result["cluster_state"] = cluster_info.get("cluster_state", "unknown")
                    result["cluster_slots_assigned"] = cluster_info.get("cluster_slots_assigned", 0)
                    result["cluster_known_nodes"] = cluster_info.get("cluster_known_nodes", 0)
                except Exception:
                    pass

            except (ConnectionError, TimeoutError, RedisError) as e:
                result["status"] = "unhealthy"
                result["error"] = str(e)
        else:
            result["status"] = "disconnected"

        return result


